import { useEffect, useState } from "react";

const REACTIONS = ["LIKE", "LOVE", "LAUGH", "DISLIKE"];

export default function CommentReactions({ commentId, username }) {
    const [summary, setSummary] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchSummary();
    }, [commentId]);

    const fetchSummary = () => {
        setLoading(true);
        fetch(
            `/api/comments/${commentId}/reactions/summary?username=${username}`
        )
            .then(r => r.json())
            .then(data => {
                setSummary(data);
                setLoading(false);
            });
    };

    const react = (type) => {
        const isSame = summary?.myReaction === type;

        const method = isSame ? "DELETE" : "POST";
        const body = isSame
            ? null
            : JSON.stringify({ reactionType: type });

        fetch(
            `/api/comments/${commentId}/reactions?username=${username}`,
            {
                method,
                headers: body
                    ? { "Content-Type": "application/json" }
                    : undefined,
                body
            }
        ).then(fetchSummary);
    };

    if (loading || !summary) return null;

    return (
        <div className="comment-reactions">
            {REACTIONS.map(type => (
                <button
                    key={type}
                    className={
                        "reaction-btn " +
                        (summary.myReaction === type ? "active" : "")
                    }
                    onClick={() => react(type)}
                >
                    {label(type)}{" "}
                    <span className="count">
                        {summary.counts[type] || 0}
                    </span>
                </button>
            ))}
        </div>
    );
}

function label(type) {
    switch (type) {
        case "LIKE": return "👍";
        case "LOVE": return "❤️";
        case "LAUGH": return "😂";
        case "DISLIKE": return "👎";
        default: return type;
    }
}
